import { useEffect, useState } from "react";
import axios from "../api/axios";

export default function MyBookings() {
  const [bookings, setBookings] = useState([]);

  const load = () => {
    axios.get("/bookings/my").then(res => setBookings(res.data));
  };

  useEffect(load, []);

  const cancel = async (id) => {
    await axios.delete(`/bookings/${id}`);
    load();
  };

  return (
    <div className="container">
      <h2 style={{ textShadow: "var(--shadow-neon-cyan)", letterSpacing: "2px", color: "var(--accent-cyan)" }}>My Bookings</h2>
      {bookings.length === 0 ? (
        <p style={{ marginTop: "20px", color: "var(--text-secondary)" }}>You have no bookings yet.</p>
      ) : (
        <>
          {/* ACTIVE BOOKINGS SECTION */}
          <h3 style={{ marginTop: '30px', marginBottom: '20px', color: 'var(--accent-green)', letterSpacing: "1px", textShadow: "var(--shadow-neon-green)" }}>Active Reservations 🟢</h3>
          <div className="grid">
            {bookings.filter(b => b.status === "Active").length === 0 ? <p style={{ color: 'var(--text-secondary)' }}>No active reservations.</p> :
              bookings.filter(b => b.status === "Active").map(b => (
                <div className="card" key={b._id} style={{ borderLeft: '5px solid var(--accent-green)' }}>
                  <h3 style={{ color: "var(--text-primary)" }}>Booking #{b._id.slice(-4)}</h3>
                  <p style={{ color: "var(--text-secondary)" }}>📍 Slot: <strong style={{ color: "var(--text-primary)" }}>{b.slotId?.slotNumber || "Unknown Slot"}</strong></p>
                  <p style={{ color: "var(--text-secondary)" }}>📅 Date: {new Date(b.startTime).toLocaleDateString()}</p>
                  <p style={{ color: "var(--text-secondary)" }}>🕒 Time: {new Date(b.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} - {new Date(b.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                  <button
                    onClick={() => cancel(b._id)}
                    style={{ background: "rgba(239, 68, 68, 0.1)", color: "var(--status-danger)", border: "1px solid var(--status-danger)", marginTop: '15px' }}
                    className="btn-primary"
                  >
                    Cancel Reservation
                  </button>
                </div>
              ))
            }
          </div>

          {/* HISTORY SECTION */}
          <h3 style={{ marginTop: '50px', marginBottom: '20px', color: 'var(--text-secondary)', borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: '20px', letterSpacing: "1px" }}>Booking History 📜</h3>
          <div className="grid">
            {bookings.filter(b => b.status !== "Active").length === 0 ? <p style={{ color: 'var(--text-secondary)' }}>No past history.</p> :
              bookings.filter(b => b.status !== "Active").map(b => (
                <div className="card" key={b._id} style={{ opacity: 0.6, background: 'rgba(255,255,255,0.02)', borderLeft: b.status === 'Completed' ? '5px solid var(--text-secondary)' : '5px solid var(--accent-pink)' }}>
                  <h3 style={{ color: 'var(--text-secondary)' }}>Booking #{b._id.slice(-4)} <span style={{ fontSize: '0.6em', background: b.status === 'Completed' ? 'rgba(255,255,255,0.1)' : 'rgba(255, 42, 95, 0.2)', color: 'white', padding: '3px 8px', borderRadius: '4px', verticalAlign: 'middle', textShadow: b.status === 'Completed' ? 'none' : 'var(--shadow-neon-pink)' }}>{b.status}</span></h3>
                  <p style={{ color: "var(--text-secondary)" }}>📍 Slot: <strong>{b.slotId?.slotNumber || "Unknown Slot"}</strong></p>
                  <p style={{ color: "var(--text-secondary)" }}>📅 Date: {new Date(b.startTime).toLocaleDateString()}</p>
                  <p style={{ color: "var(--text-secondary)" }}>🕒 Time: {new Date(b.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} - {new Date(b.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                </div>
              ))
            }
          </div>
        </>
      )}
    </div>
  );
}
